// n8n's HTTP Request node may return the array as a single item (json=array)
// or split it into one item per element (each json=supplier). Handle both.
const items = $input.all();
const list = items.flatMap((i) => {
  const j = i.json;
  if (Array.isArray(j)) return j;
  // Sometimes the response is wrapped: { data: [...] } or { body: [...] }
  if (j && Array.isArray(j.data)) return j.data;
  if (j && Array.isArray(j.body)) return j.body;
  return j && typeof j === 'object' ? [j] : [];
});
const vg = list.find((s) => s && s.slug === 'vg-ops');
if (!vg) {
  throw new Error(`VG OPS supplier not found. Saw ${list.length} suppliers: ${list.map(s => s?.slug).join(',')}`);
}
if (!vg.is_active) {
  throw new Error("VG OPS supplier is_active=false. Flip it: UPDATE suppliers SET is_active=true WHERE slug='vg-ops';");
}
return [{ json: { vg_sid: vg.id, vg_name: vg.name } }];

// n8n's OnPrintShop node flattens the GraphQL response: one item per category.
// Each json has: category_id, parent_id (-1 for root), category_name, sort_order,
// status (0=inactive), category_url, category_image, short_description.
const rows = $input.all().flatMap((item) => {
  const j = item.json ?? {};
  if (Array.isArray(j)) return j;
  const nested = j?.data?.product_category?.product_category;
  if (Array.isArray(nested)) return nested;
  return [j];
});

const parentOf = (c) => {
  const raw = c.parent_id ?? c.parent_category_id ?? c.parentId;
  if (raw === undefined || raw === null) return null;
  const s = String(raw);
  // OPS uses -1 for "no parent" (root-level category).
  if (s === '-1' || s === '0') return null;
  return s;
};

return rows
  .filter((c) => c && (c.category_id ?? c.categoryId ?? c.id))
  .map((c) => ({
    json: {
      external_id: String(c.category_id ?? c.categoryId ?? c.id),
      name: c.category_name ?? c.name ?? 'Unnamed',
      parent_external_id: parentOf(c),
      sort_order: Number(c.sort_order ?? c.display_order ?? 0),
    },
  }));

// Build category map from the prior Shape Categories node.
const catItems = $('Shape Categories').all();
const catMap = new Map(catItems.map((i) => [i.json.external_id, i.json.name]));

// Flatten any OPS response shape:
//  A) { data: { products_details: { products: [...] } } }
//  B) flat product objects per item
const flatProducts = $input.all().flatMap((item) => {
  const j = item.json ?? {};
  const nested = j?.data?.products_details?.products;
  if (Array.isArray(nested)) return nested;
  if (Array.isArray(j)) return j;
  if (j && typeof j === 'object' && (j.products_id || j.product_id || j.id)) return [j];
  return [];
});

return flatProducts.map((p) => {
  const catExt = p.default_category_id ? String(p.default_category_id) : null;
  const variants = (p.product_size ?? []).map((s) => ({
    part_id: String(s.product_size_id ?? s.size_id ?? ''),
    color: s.product_default_color ?? s.color ?? null,
    size: s.product_size_label ?? s.size_label ?? null,
    sku: s.product_size_sku ?? String(s.product_size_id ?? ''),
    base_price: null,
    inventory: null,
    warehouse: null,
  }));

  const images = [];
  if (p.small_image) images.push({ url: p.small_image, image_type: 'front', color: null, sort_order: 0 });
  if (p.large_image && p.large_image !== p.small_image) {
    images.push({ url: p.large_image, image_type: 'back', color: null, sort_order: 1 });
  }

  const options = (p.product_additional_options ?? [])
    .map((o, i) => {
      const key = o.option_key ?? o.optionKey ?? '';
      const title = o.title ?? o.option_title ?? o.optionTitle ?? key ?? 'Option';
      return {
        option_key: String(key),
        title: String(title),
        options_type: o.options_type ?? o.optionsType ?? null,
        sort_order: Number(o.sort_order ?? o.sortOrder ?? i),
        master_option_id: o.master_option_id != null ? Number(o.master_option_id) : null,
        ops_option_id: o.product_additional_option_id != null ? Number(o.product_additional_option_id) : null,
        required: Boolean(o.required),
        attributes: o.attributes ?? [],
      };
    })
    .filter((o) => o.option_key);

  return {
    json: {
      supplier_sku: p.products_sku ?? p.main_sku ?? String(p.products_id ?? p.product_id ?? ''),
      product_name: p.products_title ?? p.product_name ?? 'Untitled',
      brand: p.brand_name ?? null,
      description: p.products_description ?? p.description ?? null,
      product_type: 'apparel',
      image_url: p.small_image ?? p.large_image ?? null,
      ops_product_id: String(p.products_id ?? p.product_id ?? ''),
      external_catalogue: p.externalCatalogue != null ? Number(p.externalCatalogue) : null,
      category_external_id: catExt,
      category_name: catExt ? (catMap.get(catExt) ?? null) : null,
      variants,
      images,
      options,
    },
  };
});
